exec("""from __future__ import annotations\nimport csv, json, os, re, time\nfrom dataclasses import asdict, dataclass\nfrom datetime import datetime, timedelta, timezone\nfrom pathlib import Path\nfrom urllib.parse import urljoin\nimport requests\nfrom bs4 import BeautifulSoup\ntry:\n    from openpyxl import Workbook\nexcept Exception:\n    Workbook = None\nROOT = Path(__file__).resolve().parents[1]\nOUTPUT_DIR = ROOT / 'output'\nJST = timezone(timedelta(hours=9), 'JST')\nDEFAULT_BASE_URL = 'https://newenoking-kaitori.com'\nUSER_AGENT = os.getenv('ENOKING_USER_AGENT', 'Mozilla/5.0 (compatible; EnokingCloudMonitor/2.1)')\nREQUEST_TIMEOUT_SEC = int(os.getenv('REQUEST_TIMEOUT_SEC', '25'))\nREQUEST_INTERVAL_SEC = float(os.getenv('REQUEST_INTERVAL_SEC', '1.0'))\nMAX_CRAWL_PAGES = int(os.getenv('ENOKING_MAX_CRAWL_PAGES', '220'))\n@dataclass\nclass CategoryLink:\n    name: str\n    url: str\n@dataclass\nclass EnokingProduct:\n    jan: str\n    product_name: str\n    category: str\n    buy_price_yen: int\n    currency: str\n    notes: str\n    cash_purchase_available: bool\n    image_url: str\n    source_url: str\n    is_featured: bool\n    scraped_at_jst: str\n    source_hash: str\ndef normalize_space(value: str) -> str:\n    return re.sub(r'\\s+', ' ', str(value).replace('　', ' ')).strip()\ndef parse_yen(value) -> int | None:\n    digits = re.sub(r'[^0-9]', '', str(value or ''))\n    return int(digits) if digits else None\ndef extract_jan(text: str) -> str | None:\n    m = re.search(r'JAN\\s*[:：]\\s*([0-9]{8,14})', str(text))\n    return m.group(1) if m else None\ndef _hash(text: str) -> str:\n    import hashlib\n    return hashlib.sha256(text.encode('utf-8', errors='ignore')).hexdigest()[:16]\ndef _session():\n    s = requests.Session()\n    s.headers.update({'User-Agent': USER_AGENT, 'Accept-Language': 'ja,en-US;q=0.9,en;q=0.8'})\n    return s\ndef _fetch(session, url: str) -> str:\n    r = session.get(url, timeout=REQUEST_TIMEOUT_SEC)\n    r.raise_for_status()\n    r.encoding = r.apparent_encoding or r.encoding\n    return r.text\ndef extract_category_links(html: str, base_url: str = DEFAULT_BASE_URL) -> list[CategoryLink]:\n    soup = BeautifulSoup(html, 'html.parser')\n    out, seen = [], set()\n    for a in soup.find_all('a', href=True):\n        href = str(a.get('href'))\n        label = normalize_space(a.get_text(' ', strip=True)).replace('▸', '').strip()\n        if label and 'cat=' in href and '/products' in href:\n            url = urljoin(base_url, href)\n            if url not in seen:\n                seen.add(url); out.append(CategoryLink(label, url))\n    return out\ndef _container_for_heading(h):\n    for p in [h.parent] + list(h.parents):\n        if not p:\n            continue\n        txt = p.get_text(' ', strip=True)\n        if 'JAN' in txt and '参考買取金額' in txt and len(txt) < 2200:\n            return p\n    return h.parent\ndef _lines(tag):\n    return [normalize_space(x) for x in tag.get_text('\\n', strip=True).splitlines() if normalize_space(x)]\ndef _category(lines, name, fallback):\n    if name in lines:\n        idx = lines.index(name)\n        for c in reversed(lines[:idx]):\n            if c not in {'☆', '備考 ▼'} and not c.startswith('JAN') and not c.startswith('¥'):\n                return c\n    return fallback\ndef _notes(lines):\n    notes, on = [], False\n    for line in lines:\n        if line == '参考買取金額':\n            on = True; continue\n        if line == '商品数':\n            break\n        if on and not line.startswith('¥') and line not in {'店舗ごとの買取金額を見る', '店舗ごとの買取金額を見る 現金買取可能', '現金買取可能'}:\n            notes.append(line)\n    return ' / '.join(dict.fromkeys(notes))\ndef parse_products_from_html(html: str, source_url: str, fallback_category: str = '', scraped_at_jst: str | None = None) -> list[EnokingProduct]:\n    soup = BeautifulSoup(html, 'html.parser')\n    base_url = DEFAULT_BASE_URL\n    scraped_at = scraped_at_jst or datetime.now(JST).strftime('%Y-%m-%d %H:%M:%S %Z')\n    products = []\n    for h in soup.find_all(['h2', 'h3']):\n        name = normalize_space(h.get_text(' ', strip=True))\n        if not name:\n            continue\n        c = _container_for_heading(h)\n        if c is None:\n            continue\n        raw = c.get_text('\\n', strip=True)\n        if 'JAN' not in raw or '参考買取金額' not in raw:\n            continue\n        jan = extract_jan(raw)\n        m = re.search(r'参考買取金額\\s*\\n?\\s*¥?\\s*([0-9,]+)', raw)\n        price = parse_yen(m.group(1)) if m else None\n        if not jan or price is None:\n            continue\n        lines = _lines(c)\n        img = c.find('img')\n        img_url = urljoin(base_url, img.get('src')) if img and img.get('src') else ''\n        products.append(EnokingProduct(jan, name, _category(lines, name, fallback_category), price, 'JPY', _notes(lines), '現金買取可能' in raw, img_url, source_url, '/featured' in source_url, scraped_at, _hash(raw)))\n    return products\ndef _page_links(html: str, current: str, base_url: str = DEFAULT_BASE_URL):\n    soup = BeautifulSoup(html, 'html.parser')\n    out = []\n    for a in soup.find_all('a', href=True):\n        label = normalize_space(a.get_text(' ', strip=True))\n        href = str(a.get('href'))\n        if '次へ' in label or re.fullmatch(r'[0-9]+', label or ''):\n            u = urljoin(base_url, href)\n            if u != current and ('/products' in u or '/featured' in u):\n                out.append(u)\n    return list(dict.fromkeys(out))\ndef dedupe_products(products):\n    d = {}\n    for p in products:\n        if p.jan not in d or p.buy_price_yen > d[p.jan].buy_price_yen:\n            d[p.jan] = p\n    return sorted(d.values(), key=lambda x: (x.category, x.product_name, x.jan))\ndef crawl_enoking_products(base_url: str = DEFAULT_BASE_URL) -> list[EnokingProduct]:\n    s = _session(); queue = [(urljoin(base_url, '/featured'), '注目商品'), (urljoin(base_url, '/products'), '')]; seen = set(); out = []; scraped_at = datetime.now(JST).strftime('%Y-%m-%d %H:%M:%S %Z')\n    while queue and len(seen) < MAX_CRAWL_PAGES:\n        url, cat = queue.pop(0)\n        if url in seen:\n            continue\n        seen.add(url)\n        html = _fetch(s, url)\n        out.extend(parse_products_from_html(html, url, cat, scraped_at))\n        if url.endswith('/products'):\n            queue.extend((c.url, c.name) for c in extract_category_links(html, base_url) if c.url not in seen)\n        queue.extend((u, cat) for u in _page_links(html, url, base_url) if u not in seen)\n        if REQUEST_INTERVAL_SEC > 0 and queue:\n            time.sleep(REQUEST_INTERVAL_SEC)\n    return dedupe_products(out)\ndef product_to_dict(product):\n    return asdict(product) if hasattr(product, '__dataclass_fields__') else dict(product)\ndef write_csv(products, path: Path):\n    path.parent.mkdir(parents=True, exist_ok=True)\n    rows = [product_to_dict(p) for p in products]\n    fields = list(rows[0].keys()) if rows else ['message']\n    with path.open('w', encoding='utf-8-sig', newline='') as f:\n        w = csv.DictWriter(f, fieldnames=fields); w.writeheader(); w.writerows(rows or [{'message':'NO_PRODUCTS'}])\ndef write_json(products, path: Path):\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(json.dumps([product_to_dict(p) for p in products], ensure_ascii=False, indent=2), encoding='utf-8')\ndef write_xlsx(products, path: Path):\n    if Workbook is None:\n        return\n    path.parent.mkdir(parents=True, exist_ok=True); wb = Workbook(); ws = wb.active; ws.title = 'EnokingProducts'; rows = [product_to_dict(p) for p in products]; fields = list(rows[0].keys()) if rows else ['message']; ws.append(fields)\n    for row in rows or [{'message':'NO_PRODUCTS'}]:\n        ws.append([row.get(k) for k in fields])\n    wb.save(path)\ndef write_outputs(products, output_dir: Path = OUTPUT_DIR):\n    output_dir.mkdir(parents=True, exist_ok=True); stamp = datetime.now(JST).strftime('%Y%m%d_%H%M%S')\n    paths = {'csv': output_dir / f'enoking_products_{stamp}.csv', 'json': output_dir / f'enoking_products_{stamp}.json', 'xlsx': output_dir / f'enoking_products_{stamp}.xlsx', 'latest_csv': output_dir / 'latest_enoking_products.csv', 'latest_json': output_dir / 'latest_enoking_products.json', 'latest_xlsx': output_dir / 'latest_enoking_products.xlsx'}\n    write_csv(products, paths['csv']); write_json(products, paths['json']); write_xlsx(products, paths['xlsx']); write_csv(products, paths['latest_csv']); write_json(products, paths['latest_json']); write_xlsx(products, paths['latest_xlsx'])\n    return {k: str(v) for k, v in paths.items()}\ndef main():\n    products = crawl_enoking_products(os.getenv('ENOKING_BASE_URL', DEFAULT_BASE_URL)); paths = write_outputs(products); print(json.dumps({'product_count': len(products), 'outputs': paths}, ensure_ascii=False, indent=2)); return 0\nif __name__ == '__main__':\n    raise SystemExit(main())\n""")